class Solution(object):
    def areSimilar(self, mat, k):
        cols = len(mat[0])
        shift = k % cols
        if shift == 0:
            return True
        for i, row in enumerate(mat):
            if i % 2 == 0:
                rotated = row[-shift:] + row[:-shift]
            else:
                rotated = row[shift:] + row[:shift]
        return all(
            (mat[i][-shift:] + mat[i][:-shift] if i % 2 == 0 else mat[i][shift:] + mat[i][:shift]) == mat[i]
            for i in range(len(mat))
        )
